def rotate_right(nums: list[int], k: int) -> list[int]:
    if not nums:
        return []
    n = len(nums)
    k = k % n
    return nums[-k:] + nums[:-k] if k else nums[:]

def rotate_right(nums: list[int], k: int) -> list[int]:
    n = len(nums)
    if n == 0:
        return []

    # Handle k >= len and negative k
    k = k % n

    # If k is 0 after modulo, no rotation needed
    if k == 0:
        return list(nums)

    # Rotate right by k:
    # The last k elements move to the front
    # The first n-k elements move to the back
    return nums[n-k:] + nums[:n-k]

def rotate_right(nums: list[int], k: int) -> list[int]:
    if not nums:
        return []
    n = len(nums)
    shift = k % n
    return nums[-shift:] + nums[:-shift] if shift != 0 else nums[:]
